import pandas as pd, numpy as np
nav=pd.read_csv('data/rating_8l_BC_prodspec_navs.csv',index_col=0,parse_dates=True)
# regime_size == rating-demote (sizing inert). Compare base vs regime_size drawdown per episode.
def underwater_episodes(s, thr=-0.06):
    s=s.dropna(); peak=s.cummax(); dd=(s-peak)/peak
    eps=[]; in_ep=False; start=None; trough=None; tdate=None; pkdate=None
    for d,v in dd.items():
        if v<0 and not in_ep:
            in_ep=True; start=d; trough=v; tdate=d; pkdate=peak.index[peak.index.get_loc(d)]
        elif in_ep:
            if v<trough: trough=v; tdate=d
            if v>=-1e-9:  # recovered
                if trough<=thr: eps.append((start,tdate,trough))
                in_ep=False
    if in_ep and trough<=thr: eps.append((start,tdate,trough))
    return eps
for sysn in ['V1','V4']:
    print(f'=== {sysn}: base drawdown episodes (>=6%) vs rating-demote in SAME window ===')
    b=nav[f'base_{sysn}']; r=nav[f'regime_size_{sysn}']
    for (st,tr,ddb) in underwater_episodes(b):
        win_b=b[st:tr]; win_r=r[st:tr]
        ddb_=(win_b/win_b.cummax()-1).min()*100
        ddr_=(win_r/win_r.cummax()-1).min()*100
        print(f'  {st.date()} -> {tr.date()}:  base {ddb_:6.1f}%   rating {ddr_:6.1f}%   ({ddr_-ddb_:+.1f}pp)')
"

